using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

CI MAXN=1e5+5;
struct d
{
    int x,y;
    bool operator < (const d &b) const
    {
        return x<b.x;
    }
}p[MAXN];
struct e
{
    int f,t,w;
    bool operator < (const e &b) const
    {
        return w<b.w;
    }
}ed[26*MAXN];
int n,f[MAXN],ans,c;
int find(int x)
{
    if(f[x]==x)return x;
    return f[x]=find(f[x]);
}
signed main(void)
{
    n=read();
    FOR(i,1,n)
    {
        p[i].x=read(),p[i].y=read();
    }
    FOR(i,1,n)
    {
        f[i]=i;
    }
    sort(p+1,p+1+n);
    FOR(i,1,n)
    {
        FOR(j,i,min(i+25,n))
        {
            ed[++c].f=i;
            ed[c].t=j;
            ed[c].w=(p[i].x-p[j].x)*(p[i].x-p[j].x)+(p[i].y-p[j].y)*(p[i].y-p[j].y);
        }
    }
    sort(ed+1,ed+1+c);
    FOR(i,1,c)
    {
        int x=find(ed[i].f),y=find(ed[i].t);
        if(x==y)continue;
        ans+=ed[i].w;
        f[x]=y;
    }
    write(ans);
    return false;
}
